output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
SELECT ?person ?personLabel ?birthDate WHERE {
  VALUES ?occupation {
    wd:Q13474373
  }
  ?person wdt:P31 wd:Q5 ; wdt:P106 ?occupation ; wdt:P569 ?birthDate .
  FILTER NOT EXISTS {
    ?person wdt:P570 ?deathDate
  }
  ?person p:P106 ?statement .
  ?statement ps:P106 ?occupation .
  OPTIONAL {
    ?statement pq:P582 ?endDate
  }
  FILTER(! BOUND(?endDate) || ?endDate > NOW ())
  OPTIONAL {
    ?person rdfs:label ?personLabel .
    FILTER(LANG(?personLabel) = "en")
  }
}
ORDER BY ASC(?birthDate)
LIMIT 1

